import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Quantum-Resistant Cryptography",
  subtitle: "Post-quantum cryptographic algorithms for future-proof security",
  description: "Prepare for the quantum computing era with our advanced quantum-resistant cryptography. We implement ML-KEM, SLH-DSA, and hybrid classical + quantum-resistant encryption to protect your data against both current and future threats. Stay ahead of quantum computing advances with our future-proof cryptographic solutions.",
  benefits: [
    "Post-quantum cryptographic algorithms (ML-KEM, SLH-DSA)",
    "Hybrid classical + quantum-resistant encryption",
    "Automated key rotation with quantum RNG",
    "Future-proof your security infrastructure",
    "Compliance with emerging quantum安全 standards"
  ],
  features: [
    { title: "ML-KEM Encryption", description: "Module-Lattice-Based Key-Encapsulation Mechanism" },
    { title: "SLH-DSA Signatures", description: "Stateless Hash-Based Digital Signature Algorithm" },
    { title: "Hybrid Encryption", description: "Combine classical and quantum-resistant algorithms" },
    { title: "Quantum RNG", description: "True random number generation for cryptographic keys" },
    { title: "Key Management", description: "Automated key rotation and lifecycle management" }
  ],
  howItWorks: [
    { title: "Algorithm Selection", description: "Choose appropriate quantum-resistant algorithms" },
    { title: "Key Generation", description: "Generate keys using quantum random number generation" },
    { title: "Hybrid Encryption", description: "Apply both classical and quantum-resistant encryption" },
    { title: "Automated Rotation", description: "Keys are automatically rotated at defined intervals" }
  ],
  color: "#8b5cf6",
  icon: "M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4",
  gradient: "from-purple-500 to-violet-600"
};

function QuantumCrypto() {
  return <FeatureDetail {...pageData} />;
}

export default QuantumCrypto;
